// ─────────────────────────────────────────────
// VHSYS :: cc_report
// Rota   : POST /cc_report
// Fase 3 : Fluxo CC_REPORT completo
// ─────────────────────────────────────────────
// Input  : { data: {...}, type: 'entrada'|'saida', cc_id: string }
// Output : { message: 'GET A NEW CC_REPORT BY CC id' } HTTP 201
// Banco  : INSERT/DELETE relatorio_cc + UPDATE update_cc_report_status
// Chave  : ID = SHA-256(INDEX-CC_ID-NOME_DESPESA-VENCIMENTO-...)
// ─────────────────────────────────────────────

const body = $input.first().json.body || $input.first().json;

if (!body.data || !body.type || !body.cc_id) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Missing required fields: data, type, cc_id' }
  };
}

if (body.type !== 'entrada' && body.type !== 'saida') {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Invalid type: must be "entrada" or "saida"' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'cc_report_received',
  cc_id: body.cc_id,
  type: body.type,
  level: 'info'
}));

return { _valid: true, ...body };

// ── Decode HTML entities + Transform ──
// Combina decode + transform em 1 nó para evitar problema
// de passar contexto entre nós separados.

const payload = $input.first().json;

// Decode HTML entities recursivamente
function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g,  '&')
      .replace(/&lt;/g,   '<')
      .replace(/&gt;/g,   '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g,  "'")
      .replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

const decoded   = decodeHtml(payload);
const ccData    = decoded.data;
const type      = decoded.type;
const ccId      = decoded.cc_id;

// Verificar se a página tem dados válidos
if (!ccData || !ccData.source || !ccData.source.subItens) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'cc_report',
    event: 'cc_report_page_invalid',
    cc_id: ccId,
    level: 'warn'
  }));
  return { cc_id: ccId, type, records: [], valid: false };
}

const source  = ccData.source;
const ccLabel = source.itens && source.itens[0] ? source.itens[0].CentroCustos : '';
const subItens = (source.subItens && source.subItens.ID1) ? [...source.subItens.ID1] : [];

// Agrupar registros iguais e flattar com índice
// (replica lógica de group_equal_dicts do Flask)
const grouped = [];
let index = 0;
const remaining = [...subItens];
while (remaining.length > 0) {
  const current = remaining.shift();
  const group = [{ _index: index, ...current }];
  for (let i = remaining.length - 1; i >= 0; i--) {
    if (JSON.stringify(current) === JSON.stringify(remaining[i])) {
      group.push({ _index: index, ...remaining[i] });
      remaining.splice(i, 1);
    }
  }
  group.forEach(item => grouped.push(item));
  index++;
}

// Gerar tokens SHA-256
// SEED exata: "{INDEX}-{CC_ID}-{NOME_DESPESA}-{VENCIMENTO}-{FORNECEDOR}-{VALOR}-{SITUACAO}-{TYPE}-{CATEGORIA}"
const crypto = require('crypto');

const records = grouped.map(item => {
  const IDX        = item._index;
  const VENCIMENTO = item.Vencimento  || '';
  const FORNECEDOR = item.Fornecedor  || '';
  const NOME       = item.NomeDespesa || '';
  const SITUACAO   = item.Situacao    || '';
  const VALOR      = item.Valor       || '';
  const CATEGORIA  = item.Categoria   || '';

  const SEED  = `${IDX}-${ccId}-${NOME}-${VENCIMENTO}-${FORNECEDOR}-${VALOR}-${SITUACAO}-${type}-${CATEGORIA}`;
  const TOKEN = crypto.createHash('sha256').update(SEED).digest('hex');

  return {
    ID:          TOKEN,
    ID_SEED:     SEED,
    CC_LABEL:    ccLabel,
    CC_ID:       ccId,
    VENCIMENTO,
    FORNECEDOR,
    NOME_DESPESA: NOME,
    SITUACAO,
    CATEGORIA,
    VALOR,
    TYPE:        type
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'cc_report_transformed',
  cc_id: ccId,
  type,
  records_count: records.length,
  level: 'info'
}));

return { cc_id: ccId, type, cc_label: ccLabel, records, valid: true };

// ── Calcular diff: o que inserir e o que deletar ──
// Bug E corrigido: não usar $input.last().
// O nó Postgres devolve os registros do banco como items.
// Os dados do Transform chegam via o mesmo fluxo linear:
// cada item do Postgres tem o campo json com os IDs do banco.
// Para recuperar o contexto do Transform usamos $('Decode + Transform').first()

const transformCtx = $('Decode + Transform').first().json;
const cc_id    = transformCtx.cc_id;
const type     = transformCtx.type;
const cc_label = transformCtx.cc_label;
const records  = transformCtx.records;
const valid    = transformCtx.valid;

// Se página inválida, pular insert/delete e só atualizar status
if (!valid || records.length === 0) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'cc_report',
    event: 'cc_report_empty_page',
    cc_id,
    type,
    level: 'warn'
  }));
  return { cc_id, type, to_insert: [], to_delete: [] };
}

// IDs da API
const apiIds = new Set(records.map(r => r.ID));

// IDs do banco (podem vir como array de items ou vazio)
const dbItems  = $input.all();
const dbIds    = new Set(
  dbItems
    .map(i => i.json.ID)
    .filter(id => id !== undefined && id !== null)
);

const toInsert = records.filter(r => !dbIds.has(r.ID));
const toDelete = [...dbIds].filter(id => !apiIds.has(id));

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'cc_report_diff',
  cc_id,
  type,
  to_insert: toInsert.length,
  to_delete: toDelete.length,
  level: 'info'
}));

return { cc_id, type, cc_label, to_insert: toInsert, to_delete: toDelete };

// Expande cada record para um item separado, mantendo contexto cc_id/type
const ctx = $input.first().json;
return ctx.to_insert.map(record => ({
  cc_id:    ctx.cc_id,
  type:     ctx.type,
  cc_label: ctx.cc_label,
  record
}));

// Expande cada ID a deletar para um item separado
const ctx = $input.first().json;
return ctx.to_delete.map(id => ({
  cc_id: ctx.cc_id,
  type:  ctx.type,
  id_to_delete: id
}));

// ── Preparar dados para Update Status ──
// Bug G/H corrigido: recuperar cc_id e type do contexto
// do Calculate Diff independentemente do caminho percorrido.
const ctx = $('Calculate Diff').first().json;
return {
  cc_id: ctx.cc_id,
  type:  ctx.type
};

// Bug F corrigido: retornar statusCode + body
const ctx = $('Calculate Diff').first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'cc_report_completed',
  cc_id: ctx.cc_id,
  type:  ctx.type,
  inserted: ctx.to_insert ? ctx.to_insert.length : 0,
  deleted:  ctx.to_delete ? ctx.to_delete.length : 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { message: 'GET A NEW CC_REPORT BY CC id' }
};

const input = $input.first().json;
return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};
